import{_ as i,o as a,c as n,ai as s}from"./chunks/framework.CsYGeNYI.js";const h=JSON.parse('{"title":"Formal Verification (Security Models)","description":"","frontmatter":{"title":"Formal Verification (Security Models)","summary":"Machine-checked security models for OpenSoul’s highest-risk paths.","permalink":"/security/formal-verification/"},"headers":[],"relativePath":"security/formal-verification.md","filePath":"security/formal-verification.md","lastUpdated":1771906665000}'),o={name:"security/formal-verification.md"};function t(r,e,l,c,d,p){return a(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="formal-verification-security-models" tabindex="-1"><a class="header-anchor" href="#formal-verification-security-models">#</a> Formal Verification (Security Models)</h1><p>This page tracks OpenSoul’s <strong>formal security models</strong> (TLA+/TLC today; more as needed).</p><blockquote><p>Note: some older links may refer to the previous project name.</p></blockquote><p><strong>Goal (north star):</strong> provide a machine-checked argument that OpenSoul enforces its intended security policy (authorization, session isolation, tool gating, and misconfiguration safety), under explicit assumptions.</p><p><strong>What this is (today):</strong> an executable, attacker-driven <strong>security regression suite</strong>:</p><ul><li>Each claim has a runnable model-check over a finite state space.</li><li>Many claims have a paired <strong>negative model</strong> that produces a counterexample trace for a realistic bug class.</li></ul><p><strong>What this is not (yet):</strong> a proof that “OpenSoul is secure in all respects” or that the full TypeScript implementation is correct.</p><h2 id="where-the-models-live" tabindex="-1"><a class="header-anchor" href="#where-the-models-live">#</a> Where the models live</h2><p>Models are maintained in a separate repo: <a href="https://github.com/vignesh07/opensoul-formal-models" target="_blank" rel="noreferrer">vignesh07/opensoul-formal-models</a>.</p><h2 id="important-caveats" tabindex="-1"><a class="header-anchor" href="#important-caveats">#</a> Important caveats</h2><ul><li>These are <strong>models</strong>, not the full TypeScript implementation. Drift between model and code is possible.</li><li>Results are bounded by the state space explored by TLC; “green” does not imply security beyond the modeled assumptions and bounds.</li><li>Some claims rely on explicit environmental assumptions (e.g., correct deployment, correct configuration inputs).</li></ul><h2 id="reproducing-results" tabindex="-1"><a class="header-anchor" href="#reproducing-results">#</a> Reproducing results</h2><p>Today, results are reproduced by cloning the models repo locally and running TLC (see below). A future iteration could offer:</p><ul><li>CI-run models with public artifacts (counterexample traces, run logs)</li><li>a hosted “run this model” workflow for small, bounded checks</li></ul><p>Getting started:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/vignesh07/opensoul-formal-models</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> opensoul-formal-models</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Java 11+ required (TLC runs on the JVM).</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># The repo vendors a pinned \`tla2tools.jar\` (TLA+ tools) and provides \`bin/tlc\` + Make targets.</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">targe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">t</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h3 id="gateway-exposure-and-open-gateway-misconfiguration" tabindex="-1"><a class="header-anchor" href="#gateway-exposure-and-open-gateway-misconfiguration">#</a> Gateway exposure and open gateway misconfiguration</h3><p><strong>Claim:</strong> binding beyond loopback without auth can make remote compromise possible / increases exposure; token/password blocks unauth attackers (per the model assumptions).</p><ul><li>Green runs: <ul><li><code>make gateway-exposure-v2</code></li><li><code>make gateway-exposure-v2-protected</code></li></ul></li><li>Red (expected): <ul><li><code>make gateway-exposure-v2-negative</code></li></ul></li></ul><p>See also: <code>docs/gateway-exposure-matrix.md</code> in the models repo.</p><h3 id="nodes-run-pipeline-highest-risk-capability" tabindex="-1"><a class="header-anchor" href="#nodes-run-pipeline-highest-risk-capability">#</a> Nodes.run pipeline (highest-risk capability)</h3><p><strong>Claim:</strong> <code>nodes.run</code> requires (a) node command allowlist plus declared commands and (b) live approval when configured; approvals are tokenized to prevent replay (in the model).</p><ul><li>Green runs: <ul><li><code>make nodes-pipeline</code></li><li><code>make approvals-token</code></li></ul></li><li>Red (expected): <ul><li><code>make nodes-pipeline-negative</code></li><li><code>make approvals-token-negative</code></li></ul></li></ul><h3 id="pairing-store-dm-gating" tabindex="-1"><a class="header-anchor" href="#pairing-store-dm-gating">#</a> Pairing store (DM gating)</h3><p><strong>Claim:</strong> pairing requests respect TTL and pending-request caps.</p><ul><li>Green runs: <ul><li><code>make pairing</code></li><li><code>make pairing-cap</code></li></ul></li><li>Red (expected): <ul><li><code>make pairing-negative</code></li><li><code>make pairing-cap-negative</code></li></ul></li></ul><h3 id="ingress-gating-mentions-control-command-bypass" tabindex="-1"><a class="header-anchor" href="#ingress-gating-mentions-control-command-bypass">#</a> Ingress gating (mentions + control-command bypass)</h3><p><strong>Claim:</strong> in group contexts requiring mention, an unauthorized “control command” cannot bypass mention gating.</p><ul><li>Green: <ul><li><code>make ingress-gating</code></li></ul></li><li>Red (expected): <ul><li><code>make ingress-gating-negative</code></li></ul></li></ul><h3 id="routing-session-key-isolation" tabindex="-1"><a class="header-anchor" href="#routing-session-key-isolation">#</a> Routing/session-key isolation</h3><p><strong>Claim:</strong> DMs from distinct peers do not collapse into the same session unless explicitly linked/configured.</p><ul><li>Green: <ul><li><code>make routing-isolation</code></li></ul></li><li>Red (expected): <ul><li><code>make routing-isolation-negative</code></li></ul></li></ul><h2 id="v1-additional-bounded-models-concurrency-retries-trace-correctness" tabindex="-1"><a class="header-anchor" href="#v1-additional-bounded-models-concurrency-retries-trace-correctness">#</a> v1++: additional bounded models (concurrency, retries, trace correctness)</h2><p>These are follow-on models that tighten fidelity around real-world failure modes (non-atomic updates, retries, and message fan-out).</p><h3 id="pairing-store-concurrency-idempotency" tabindex="-1"><a class="header-anchor" href="#pairing-store-concurrency-idempotency">#</a> Pairing store concurrency / idempotency</h3><p><strong>Claim:</strong> a pairing store should enforce <code>MaxPending</code> and idempotency even under interleavings (i.e., “check-then-write” must be atomic / locked; refresh shouldn’t create duplicates).</p><p>What it means:</p><ul><li><p>Under concurrent requests, you can’t exceed <code>MaxPending</code> for a channel.</p></li><li><p>Repeated requests/refreshes for the same <code>(channel, sender)</code> should not create duplicate live pending rows.</p></li><li><p>Green runs:</p><ul><li><code>make pairing-race</code> (atomic/locked cap check)</li><li><code>make pairing-idempotency</code></li><li><code>make pairing-refresh</code></li><li><code>make pairing-refresh-race</code></li></ul></li><li><p>Red (expected):</p><ul><li><code>make pairing-race-negative</code> (non-atomic begin/commit cap race)</li><li><code>make pairing-idempotency-negative</code></li><li><code>make pairing-refresh-negative</code></li><li><code>make pairing-refresh-race-negative</code></li></ul></li></ul><h3 id="ingress-trace-correlation-idempotency" tabindex="-1"><a class="header-anchor" href="#ingress-trace-correlation-idempotency">#</a> Ingress trace correlation / idempotency</h3><p><strong>Claim:</strong> ingestion should preserve trace correlation across fan-out and be idempotent under provider retries.</p><p>What it means:</p><ul><li><p>When one external event becomes multiple internal messages, every part keeps the same trace/event identity.</p></li><li><p>Retries do not result in double-processing.</p></li><li><p>If provider event IDs are missing, dedupe falls back to a safe key (e.g., trace ID) to avoid dropping distinct events.</p></li><li><p>Green:</p><ul><li><code>make ingress-trace</code></li><li><code>make ingress-trace2</code></li><li><code>make ingress-idempotency</code></li><li><code>make ingress-dedupe-fallback</code></li></ul></li><li><p>Red (expected):</p><ul><li><code>make ingress-trace-negative</code></li><li><code>make ingress-trace2-negative</code></li><li><code>make ingress-idempotency-negative</code></li><li><code>make ingress-dedupe-fallback-negative</code></li></ul></li></ul><h3 id="routing-dmscope-precedence-identitylinks" tabindex="-1"><a class="header-anchor" href="#routing-dmscope-precedence-identitylinks">#</a> Routing dmScope precedence + identityLinks</h3><p><strong>Claim:</strong> routing must keep DM sessions isolated by default, and only collapse sessions when explicitly configured (channel precedence + identity links).</p><p>What it means:</p><ul><li><p>Channel-specific dmScope overrides must win over global defaults.</p></li><li><p>identityLinks should collapse only within explicit linked groups, not across unrelated peers.</p></li><li><p>Green:</p><ul><li><code>make routing-precedence</code></li><li><code>make routing-identitylinks</code></li></ul></li><li><p>Red (expected):</p><ul><li><code>make routing-precedence-negative</code></li><li><code>make routing-identitylinks-negative</code></li></ul></li></ul>`,46)])])}const m=i(o,[["render",t]]);export{h as __pageData,m as default};
